  ?agent dct:identifier ?identifier .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . FILTER(LANG(?title) = "it") }
}
LIMIT 10

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?dataset ?title ?publisher_name ?role WHERE {
  ?agent dct:identifier "c_l219" .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . FILTER(LANG(?title) = "it") }
  OPTIONAL { ?agent foaf:name ?publisher_name }
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>

SELECT DISTINCT ?dataset ?title ?modified
WHERE {
  ?dataset a dcat:Dataset ;
           dcterms:title ?title .
  ?dataset dcterms:spatial <http://publications.europa.eu/resource/authority/country/GRC> .
  OPTIONAL { ?dataset dcterms:modified ?modified }
  FILTER(LANG(?title) = "en")
}
ORDER BY DESC(?modified)
LIMIT 20

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT DISTINCT ?publisherName ?dataset
WHERE {
  ?dataset a dcat:Dataset ;
           <http://data.europa.eu/r5r/applicableLegislation> <http://data.europa.eu/eli/reg_impl/2023/138/oj> ;
           dcterms:publisher ?pub .
  ?pub foaf:name ?publisherName .
  FILTER(CONTAINS(LCASE(STR(?publisherName)), "comune"))
}
LIMIT 500

SELECT DISTINCT ?item ?itemLabel ?typeLabel WHERE {
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:api "EntitySearch" ;
                    wikibase:endpoint "www.wikidata.org" ;
                    mwapi:search "Alibaba Group" ;
                    mwapi:language "en" .
    ?item wikibase:apiOutputItem mwapi:item .
  }
  ?item wdt:P31 ?type .
  FILTER(?type IN (wd:Q4830453, wd:Q6881511, wd:Q891723, wd:Q161726, wd:Q778575))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" . }
} LIMIT 5

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  FILTER(LANG(?title) = "en")
  FILTER(CONTAINS(LCASE(STR(?title)), "violence"))
}

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcat: <http://www.w3.org/ns/dcat#>

SELECT ?dataset ?title ?issued ?modified WHERE {
  ?dataset a dcat:Dataset .
  ?dataset dct:title ?title .
  FILTER(
    CONTAINS(LCASE(STR(?title)), "stradario") && CONTAINS(LCASE(STR(?title)), "caldiero") ||
    CONTAINS(LCASE(STR(?title)), "parcheggi") && CONTAINS(LCASE(STR(?title)), "storico") ||
    CONTAINS(LCASE(STR(?title)), "assenze") && CONTAINS(LCASE(STR(?title)), "taranto") ||
    CONTAINS(LCASE(STR(?title)), "pdnd") && CONTAINS(LCASE(STR(?title)), "aderenti") ||
    CONTAINS(LCASE(STR(?title)), "brevetti enea") ||
    CONTAINS(LCASE(STR(?title)), "open source") && CONTAINS(LCASE(STR(?title)), "pubblica amministrazione")
  )
  OPTIONAL { ?dataset dct:issued ?issued }
  OPTIONAL { ?dataset dct:modified ?modified }
}

SELECT ?name (COUNT(?ds) AS ?n)
WHERE {
  ?ds <http://data.europa.eu/r5r/applicableLegislation> <http://data.europa.eu/eli/reg_impl/2023/138/oj> ;
      <http://purl.org/dc/terms/publisher> [ <http://xmlns.com/foaf/0.1/name> ?name ] .
  FILTER(CONTAINS(LCASE(?name), "comune") || CONTAINS(LCASE(?name), "municipalit"))
}
GROUP BY ?name ORDER BY DESC(?n) LIMIT 200

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX schema: <http://schema.org/>

SELECT DISTINCT ?catalog ?title ?homepage ?description
WHERE {
  ?catalog a dcat:Catalog .
  ?catalog dct:spatial ?spatial .
  FILTER(CONTAINS(STR(?spatial), "EL") || CONTAINS(STR(?spatial), "greece") || CONTAINS(STR(?spatial), "GRC"))
  OPTIONAL { ?catalog dct:title ?title . FILTER(LANG(?title) = "en" || LANG(?title) = "el" || LANG(?title) = "") }
  OPTIONAL { ?catalog foaf:homepage ?homepage }
  OPTIONAL { ?catalog dct:description ?description . FILTER(LANG(?description) = "en") }
}
LIMIT 50

PREFIX dct: &lt;http://purl.org/dc/terms/&gt;
PREFIX dcat: &lt;http://www.w3.org/ns/dcat#&gt;
PREFIX foaf: &lt;http://xmlns.com/foaf/0.1/&gt;
SELECT ?title ?publisher WHERE {
  ?dataset a dcat:Dataset ;
    dct:title ?title ;
    dct:publisher ?pub .
  ?pub foaf:name ?publisher .
  FILTER(lang(?title) = "en")
  FILTER(CONTAINS(LCASE(str(?title)), "youth") &amp;&amp; CONTAINS(LCASE(str(?title)), "environment"))
}
LIMIT 10
